<template><div class="login"><el-card><h1>庆喜儿运营后台</h1><p class="muted">管理员 Token 与 MFA 由统一身份网关签发</p><el-input v-model="token" type="password" placeholder="管理员访问令牌"/><el-checkbox v-model="mfa">本次会话已完成 MFA</el-checkbox><el-button type="primary" class="full" @click="login">登录</el-button></el-card></div></template><script setup lang="ts">import{ref}from'vue';import{useRoute,useRouter}from'vue-router';import{useAdminStore}from'@/stores/admin';const token=ref(import.meta.env.DEV?'admin-token':''),mfa=ref(true),router=useRouter(),route=useRoute();function login(){if(!token.value)return;useAdminStore().login(token.value,mfa.value);router.replace(String(route.query.redirect||'/dashboard'))};</script><style scoped>.login{min-height:100vh;display:grid;place-items:center;background:linear-gradient(135deg,#eff6ff,#f8fafc)}.el-card{width:420px}.full{width:100%;margin-top:18px}.el-input,.el-checkbox{margin:12px 0}</style>
